import{_ as a,o as t,c as o,a3 as r}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"121A. Change Of Ward Allowance","description":"","frontmatter":{"title":"121A. Change Of Ward Allowance","eba":"Mental Health Services 2024-2028","topics":["hours","shift-work","rosters","allowances"]},"headers":[],"relativePath":"ebas/mental-health/health-professionals/allowances/121A-change-of-ward-allowance.md","filePath":"ebas/mental-health/health-professionals/allowances/121A-change-of-ward-allowance.md"}'),n={name:"ebas/mental-health/health-professionals/allowances/121A-change-of-ward-allowance.md"};function s(l,e,i,h,d,p){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="_121a-change-of-ward-allowance" tabindex="-1">121A. Change Of Ward Allowance <a class="header-anchor" href="#_121a-change-of-ward-allowance" aria-label="Permalink to &quot;121A. Change Of Ward Allowance&quot;">​</a></h1><p><strong>121A.1</strong> Definitions</p><p>In this clause:</p><p><strong>(a)</strong> Base Ward means the Ward or Unit to which the Employee was rostered to work in accordance with <a href="/eba/ebas/mental-health/health-professionals/hours-of-work/124-roster.html">clause 124</a> (Duty Roster).</p><p><strong>(b)</strong> Multi Base Ward Employee means an Employee who is contracted to work on more than one Base Ward.</p><p><strong>121A.2</strong> Relocation from Base Ward</p><p><strong>(a)</strong> The Employer will ensure that rosters are issued on a per ward or unit basis.</p><p><strong>(b)</strong> Where, at the initiative of the Employer, an Employee performs their rostered shift at a ward, unit or Department that is not their Base Ward, the Employee will be entitled to the Change of Ward Allowance.</p><p><strong>(c)</strong> The Change of Ward Allowance is set out in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a>.</p><p><strong>121A.3</strong> Change of Ward Allowance - exceptions The allowance in this clause does not apply to:</p><p><strong>(a)</strong> A casual Employee, including a Bank Employee</p><p><strong>(b)</strong> A Pool Employee</p><p><strong>(c)</strong> An Employee whose role is genuinely not ward/unit based, or who does not ordinarily work in a ward</p><p><strong>(d)</strong> An Employee not rostered to work in an aged care ward, undertaking ad hoc assessment or supervision duties in an aged care ward for part of a shift</p><p><strong>(e)</strong> An additional shift that a part-time Employee has agreed to work, unless relocated from the ward on which the additional shift was scheduled to take place</p><p><strong>(f)</strong> A post-registration student who is required to operate in another ward, unit or department due to their academic requirements</p><p><strong>(g)</strong> An Employee who is required to follow their patient to other units/wards e.g. ECT or</p><p><strong>(h)</strong> Working from home arrangements or other like arrangements.</p><p><strong>(i)</strong> A Multi Base Ward Employee to the extent they are working on a Base Ward in accordance with their roster. Example: An Employee is contracted to work on Ward A on some days, and Ward B on other days. Ward A and Ward B are Base Wards for the purposes of this clause. A Multi Base Ward Employee who, at the initiative of the Employer, performs their rostered shift at a ward, unit or department that is not their Base Ward, will be entitled to the Change of Ward Allowance.</p><p><strong>121A.4</strong> Anti-avoidance Employers must not seek to circumvent this provision by, for example, defining multiple wards as one ward, declaring Employees to be part of a pool arrangement or Multi Base Ward Employee contrary to their wishes, amalgamating cost centres, or not rostering to a ward, unit, clinical section or department where that would ordinarily be the case.</p><p><strong>121A.5</strong> Additional Provisions Additional provisions may apply where an Employee redeploys to another workplace (see <a href="/eba/ebas/mental-health/common-terms/allowances/35-travelling-and-reimbursement.html">clause 35</a>), or the redeployment is as a result of the Employee being an Affected Employee (see <a href="/eba/ebas/mental-health/common-terms/consultation-disputes/20-redundancy-and-associated-entitlements.html">clause 20</a>).</p>',21)])])}const g=a(n,[["render",s]]);export{m as __pageData,g as default};
